// 三载体一致:纯 JS 计算,无 DOM/shadow/uplink
import { diffChars, diffWords, diffLines, diffSentences, diffJson, diffCss } from 'https://cdn.jsdelivr.net/npm/diff@9/+esm';
const methods = { chars: diffChars, words: diffWords, lines: diffLines, sentences: diffSentences, json: diffJson, css: diffCss };
const fn = methods[data.granularity ?? 'lines'];
const changes = fn(data.oldText, data.newText, { ignoreCase: data.ignoreCase ?? false });
